changeSet.sql:
CREATE TABLE creature_types (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_creature_types_code_system ON creature_types (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_creature_types_code_owner ON creature_types (code, homebrew_id);

CREATE TABLE alignments (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_alignments_code_system ON alignments (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_alignments_code_owner ON alignments (code, homebrew_id);

CREATE TABLE languages (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_languages_code_system ON languages (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_languages_code_owner ON languages (code, homebrew_id);

CREATE TABLE sense_types (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_sense_types_code_system ON sense_types (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_sense_types_code_owner ON sense_types (code, homebrew_id);

CREATE TABLE movement_types (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_movement_types_code_system ON movement_types (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_movement_types_code_owner ON movement_types (code, homebrew_id);

CREATE TABLE habitats (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_habitats_code_system ON habitats (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_habitats_code_owner ON habitats (code, homebrew_id);

CREATE TABLE treasure_tags (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_treasure_tags_code_system ON treasure_tags (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_treasure_tags_code_owner ON treasure_tags (code, homebrew_id);

CREATE TABLE bestiary_conditions (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_bestiary_conditions_code_system ON bestiary_conditions (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_bestiary_conditions_code_owner ON bestiary_conditions (code, homebrew_id);

CREATE TABLE monster_gear_items (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_monster_gear_items_code_system ON monster_gear_items (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_monster_gear_items_code_owner ON monster_gear_items (code, homebrew_id);

CREATE TABLE sources (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    book_code   varchar(20) NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_sources_code_system ON sources (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_sources_code_owner ON sources (code, homebrew_id);

CREATE TABLE monster_creature_types (
    monster_id      uuid NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    creature_type_id uuid NOT NULL REFERENCES creature_types(id),
    PRIMARY KEY (monster_id, creature_type_id)
);

CREATE TABLE monster_speeds (
    id               uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    monster_id       uuid NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    movement_type_id uuid NOT NULL REFERENCES movement_types(id),
    ft               int  NOT NULL,
    hover            boolean NOT NULL DEFAULT false,
    UNIQUE (monster_id, movement_type_id)
);

CREATE TABLE monster_senses (
    id            uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    monster_id    uuid NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    sense_type_id uuid NOT NULL REFERENCES sense_types(id),
    ft            int  NOT NULL,
    UNIQUE (monster_id, sense_type_id)
);

CREATE TABLE monster_languages (
    monster_id  uuid NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    language_id uuid NOT NULL REFERENCES languages(id),
    PRIMARY KEY (monster_id, language_id)
);

CREATE TABLE monster_saving_throws (
    id         uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    monster_id uuid        NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    ability    varchar(20) NOT NULL,
    bonus      smallint    NOT NULL,
    UNIQUE (monster_id, ability)
);

CREATE TABLE monster_skill_proficiencies (
    id                   uuid     PRIMARY KEY DEFAULT gen_random_uuid(),
    monster_id           uuid     NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    proficiency_skill_id uuid     NOT NULL REFERENCES proficiency_skills(id),
    bonus                smallint NOT NULL,
    UNIQUE (monster_id, proficiency_skill_id)
);

CREATE TABLE monster_damage_resistances (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    monster_id  uuid        NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    damage_type varchar(20) NULL,
    note        text        NULL,
    UNIQUE (monster_id, damage_type)
);

CREATE TABLE monster_damage_immunities (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    monster_id  uuid        NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    damage_type varchar(20) NULL,
    note        text        NULL,
    UNIQUE (monster_id, damage_type)
);

CREATE TABLE monster_damage_vulnerabilities (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    monster_id  uuid        NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    damage_type varchar(20) NULL,
    note        text        NULL,
    UNIQUE (monster_id, damage_type)
);

CREATE TABLE monster_condition_immunities (
    monster_id   uuid NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    condition_id uuid NOT NULL REFERENCES bestiary_conditions(id),
    PRIMARY KEY (monster_id, condition_id)
);

CREATE TABLE monster_habitats (
    monster_id uuid NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    habitat_id uuid NOT NULL REFERENCES habitats(id),
    PRIMARY KEY (monster_id, habitat_id)
);

CREATE TABLE monster_treasures (
    monster_id      uuid NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    treasure_tag_id uuid NOT NULL REFERENCES treasure_tags(id),
    PRIMARY KEY (monster_id, treasure_tag_id)
);

CREATE TABLE monster_sources (
    monster_id uuid NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    source_id  uuid NOT NULL REFERENCES sources(id),
    PRIMARY KEY (monster_id, source_id)
);

CREATE TABLE monster_gear (
    id         uuid     PRIMARY KEY DEFAULT gen_random_uuid(),
    monster_id uuid     NOT NULL REFERENCES monsters(id) ON DELETE CASCADE,
    item_id    uuid     NOT NULL REFERENCES monster_gear_items(id),
    qty        smallint NOT NULL DEFAULT 1,
    UNIQUE (monster_id, item_id)
);
